﻿@inherits LayoutComponentBase

@code {
    [CascadingParameter]
    private WizardProgress? Progress { get; set; }
}

<div class="page">

arguments.file_text:
@{
    var steps = new[] { "Personal Info", "Experience", "References", "Review" };
    var urls = new[] { "/apply/personal-info", "/apply/experience", "/apply/references", "/apply/review" };
}

<nav class="d-flex align-items-center gap-3 w-100" aria-label="Application progress">
    <span class="fw-semibold text-nowrap">Step @Progress.CurrentStep of @WizardProgress.TotalSteps</span>
    @for (int i = 0; i < steps.Length; i++)
    {
        var step = i + 1;
        var isCurrent = step == Progress.CurrentStep;
        var isCompleted = Progress.CompletedSteps.Contains(step);
        var css = isCurrent ? "btn btn-primary btn-sm"
                 : isCompleted ? "btn btn-success btn-sm"
                 : "btn btn-outline-secondary btn-sm";

        <a href="@urls[i]" class="@css">
            @if (isCompleted && !isCurrent)
            {
                <span>✓ </span>
            }
            @steps[i]
        </a>
    }
</nav>

@code {
    [Parameter, EditorRequired]
    public WizardProgress Progress { get; set; } = default!;
}

@page "/apply/personal-info"
@rendermode InteractiveServer
@inject WizardState Wizard
@inject CascadingValueSource<WizardProgress> ProgressSource
@inject NavigationManager Nav

<PageTitle>Apply – Personal Info</PageTitle>
<h1>Step 1: Personal Information</h1>

<EditForm Model="this" OnValidSubmit="Next" FormName="personal-info">
    <div class="mb-3">
        <label class="form-label">Full Name</label>
        <InputText class="form-control" @bind-Value="Wizard.Name" />
    </div>
    <div class="mb-3">
        <label class="form-label">Email</label>
        <InputText class="form-control" @bind-Value="Wizard.Email" />
    </div>
    <button type="submit" class="btn btn-primary">Next →</button>
</EditForm>

@code {
    protected override async Task OnInitializedAsync()
    {
        await ProgressSource.NotifyChangedAsync(
            new WizardProgress(1, Wizard.CompletedSteps));
    }

    private async Task Next()
    {
        Wizard.CompletedSteps.Add(1);
        await ProgressSource.NotifyChangedAsync(
            new WizardProgress(2, Wizard.CompletedSteps));
        Nav.NavigateTo("/apply/experience");
    }
}

@page "/apply/experience"
@rendermode InteractiveServer
@inject WizardState Wizard
@inject CascadingValueSource<WizardProgress> ProgressSource
@inject NavigationManager Nav

<PageTitle>Apply – Experience</PageTitle>
<h1>Step 2: Work Experience</h1>

@foreach (var (job, index) in Wizard.JobHistory.Select((j, i) => (j, i)))
{
    <div class="card mb-3 p-3">
        <div class="mb-2">
            <label class="form-label">Company</label>
            <input class="form-control" @bind="job.Company" />
        </div>
        <div class="mb-2">
            <label class="form-label">Job Title</label>
            <input class="form-control" @bind="job.Title" />
        </div>
        <div class="mb-2">
            <label class="form-label">Years</label>
            <input class="form-control" @bind="job.Years" />
        </div>
        <button type="button" class="btn btn-outline-danger btn-sm" @onclick="() => RemoveJob(index)">
            Remove
        </button>
    </div>
}

<button type="button" class="btn btn-outline-primary mb-3" @onclick="AddJob">+ Add Job</button>

<div class="d-flex gap-2">
    <button type="button" class="btn btn-secondary" @onclick="Back">← Back</button>
    <button type="button" class="btn btn-primary" @onclick="Next">Next →</button>
</div>

@code {
    protected override async Task OnInitializedAsync()
    {
        if (Wizard.JobHistory.Count == 0)
            Wizard.JobHistory.Add(new());

        await ProgressSource.NotifyChangedAsync(
            new WizardProgress(2, Wizard.CompletedSteps));
    }

    private void AddJob() => Wizard.JobHistory.Add(new());
    private void RemoveJob(int index) => Wizard.JobHistory.RemoveAt(index);

    private async Task Back()
    {
        await ProgressSource.NotifyChangedAsync(
            new WizardProgress(1, Wizard.CompletedSteps));
        Nav.NavigateTo("/apply/personal-info");
    }

    private async Task Next()
    {
        Wizard.CompletedSteps.Add(2);
        await ProgressSource.NotifyChangedAsync(
            new WizardProgress(3, Wizard.CompletedSteps));
        Nav.NavigateTo("/apply/references");
    }
}

