@page "/apply/review"
@rendermode InteractiveServer
@inject WizardState Wizard
@inject CascadingValueSource<WizardProgress> ProgressSource
@inject NavigationManager Nav

<PageTitle>Apply – Review</PageTitle>
<h1>Step 4: Review Your Application</h1>

<div class="card mb-4 p-3">
    <h4>Personal Information</h4>
    <p><strong>Name:</strong> @Wizard.Name</p>
    <p><strong>Email:</strong> @Wizard.Email</p>
</div>

<div class="card mb-4 p-3">
    <h4>Work Experience</h4>
    @if (Wizard.JobHistory.Count == 0)
    {
        <p class="text-muted">No jobs entered.</p>
    }
    else
    {
        @foreach (var job in Wizard.JobHistory)
        {
            <div class="mb-2">
                <strong>@job.Title</strong> at @job.Company (@job.Years years)
            </div>
        }
    }
</div>

<div class="card mb-4 p-3">
    <h4>References</h4>
    @if (Wizard.References.Count == 0)
    {
        <p class="text-muted">No references entered.</p>
    }
    else
    {
        @foreach (var r in Wizard.References)
        {
            <div class="mb-2">
                <strong>@r.Name</strong> — @r.Relationship (@r.Email)
            </div>
        }
    }
</div>

<div class="d-flex gap-2">
    <button type="button" class="btn btn-secondary" @onclick="Back">← Back</button>
    <button type="button" class="btn btn-success" @onclick="Submit">Submit Application</button>
</div>

@if (submitted)
{
    <div class="alert alert-success mt-3">Application submitted successfully!</div>
}

@code {
    private bool submitted;

    protected override async Task OnInitializedAsync()
    {
        await ProgressSource.NotifyChangedAsync(
            new WizardProgress(4, Wizard.CompletedSteps));
    }

    private async Task Back()
    {
        await ProgressSource.NotifyChangedAsync(
            new WizardProgress(3, Wizard.CompletedSteps));
        Nav.NavigateTo("/apply/references");
    }

    private void Submit()
    {
        Wizard.CompletedSteps.Add(4);
        submitted = true;
    }
}

