@{
    var steps = new[] { "Personal Info", "Experience", "References", "Review" };
    var urls = new[] { "/apply/personal-info", "/apply/experience", "/apply/references", "/apply/review" };
}

<nav class="d-flex align-items-center gap-3 w-100" aria-label="Application progress">
    <span class="fw-semibold text-nowrap">Step @Progress.CurrentStep of @WizardProgress.TotalSteps</span>
    @for (int i = 0; i < steps.Length; i++)
    {
        var step = i + 1;
        var isCurrent = step == Progress.CurrentStep;
        var isCompleted = Progress.CompletedSteps.Contains(step);
        var css = isCurrent ? "btn btn-primary btn-sm"
                 : isCompleted ? "btn btn-success btn-sm"
                 : "btn btn-outline-secondary btn-sm";

        <a href="@urls[i]" class="@css">
            @if (isCompleted && !isCurrent)
            {
                <span>✓ </span>
            }
            @steps[i]
        </a>
    }
</nav>

@code {
    [Parameter, EditorRequired]
    public WizardProgress Progress { get; set; } = default!;
}

